{"code": "import json
import re
from collections import defaultdict

users_2016 = set([u['user_id'] for u in locals().get('var_functions.query_db:12', [])])
reviews = locals().get('var_functions.query_db:16', [])
businesses = locals().get('var_functions.query_db:22', [])

biz_to_cats = {}
for biz in businesses:
    desc = biz.get('description', '')
    cats = []

    if 'services in' in desc:
        m = re.search(r'services in (.+?)(?:\.|$)', desc)
        if m:
            cats = [p.strip() for p in re.split(r',\s*|\sand\s', m.group(1)) if p.strip() not in ['', 'and']]

    if not cats and 'including' in desc:
        m = re.search(r'including (.+?)(?:\.|$|\s+for|\s+making)', desc)
        if m:
            cats = [p.strip() for p in re.split(r',\s*|\sand\s', m.group(1)) if p.strip() not in ['', 'and']]

    if not cats:
        phrases = re.findall(r'\b([A-Z][a-zA-Z&\s]*)\b', desc)
        exclude = {'Located', 'at', 'in', 'and', 'or', 'this', 'that', 'facility', 'establishment', 'offers', 'services', 'range', 'including', 'for', 'making', 'your', 'making it', 'mustvisit', 'must-visit'}
        cats = [p.strip() for p in phrases if p.strip() and len(p.strip()) > 3 and p.strip() not in exclude]
        if len(cats) > 1: cats = cats[-4:]

    biz_to_cats[biz['business_id']] = cats if cats else ['Other']

cat_counts = defaultdict(int)
for rev in reviews:
    if rev['user_id'] in users_2016:
        ref_num = rev['business_ref'].split('_')[1]
        for cat in biz_to_cats.get(f'businessid_{ref_num}', ['Other']):
            cat_counts[cat] += 1

top5 = sorted(cat_counts.items(), key=lambda x: x[1], reverse=True)[:5]

result = {'top_5_categories': [{'rank': i+1, 'category': cat, 'reviews': count} for i, (cat, count) in enumerate(top5)]}

print("----BEGIN PRINT FORMAT----")
print("__RESULT__:")
print(json.dumps(result))
print("----END PRINT FORMAT----")"}

